		if (strpos($filename, realpath(__DIR__ . '/' . $this->uploadPath)) !== 0) {
			return false;
		}
		// move file to its final location
		if (!move_uploaded_file($_FILES["fields"]["tmp_name"][$field["field"]], $filename)) {
			return false;
		}
		return q($filename);
	}
}

