		if ($this->literal('@media')) {
			if (($this->mediaQueryList($mediaQueries) || true)
				&& $this->literal('{'))
			{
				$media = $this->pushSpecialBlock("media");
				$media->queries = is_null($mediaQueries) ? array() : $mediaQueries;
				return true;
			} else {
				$this->seek($s);
				return false;
			}
		}

