				}
			}
		}

		$this->seek($s);
	}

	// setting a variable
	if ($this->variable($var) && $this->assign() &&
		$this->propertyValue($value) && $this->end())
	{
		$this->append(array('assign', $var, $value), $s);
		return true;
	} else {
		$this->seek($s);
	}

